  ('Master of Science in Data Science', 'ms-data-science', 'From IIIT Bangalore & Liverpool John Moores University', 'Earn a globally recognized degree in Data Science with hands-on projects and industry mentorship from IIIT Bangalore.', 1, 'IIIT Bangalore', 'Dr. Srinath Srinivasa', 'Professor, IIIT Bangalore', 72, 325000, 450000, 1, 8999, 'Advanced', 4.8, 3240, 12500, 24, 500, 'MSc Degree', 'Python,Machine Learning,Deep Learning,NLP,Statistics,Big Data,SQL,Tableau', 'Industry projects with real datasets,Live sessions with industry mentors,500+ hours of learning,Career assistance with top companies', 1, 1, '2026-04-15'),
  ('Executive PG Programme in Management', 'epgp-management', 'From IIM Kozhikode', 'Fast-track your career with this prestigious executive management program from one of India top IIMs.', 2, 'IIM Kozhikode', 'Prof. Debashis Chatterjee', 'Director, IIM Kozhikode', 52, 280000, 375000, 1, 7499, 'Executive', 4.7, 2180, 8900, 20, 400, 'Executive PG Certificate', 'Strategic Management,Financial Management,Marketing,Operations,Leadership,Business Analytics', 'IIM Kozhikode Alumni Status,Campus immersion module,Live sessions with IIM faculty,Industry capstone project', 1, 0, '2026-05-01'),
