  ('PG Diploma in Blockchain Technology', 'blockchain-pg', 'From IIT Kanpur', 'Explore decentralized systems, smart contracts, and Web3 with IIT Kanpur experts.', 8, 'IIT Kanpur', 'Prof. Sandeep Shukla', 'Professor, IIT Kanpur', 28, 110000, 160000, 1, 3099, 'Intermediate', 4.4, 720, 2800, 12, 260, 'PG Diploma', 'Solidity,Ethereum,Smart Contracts,DeFi,NFTs,Hyperledger,Cryptography,Web3', 'Build and deploy smart contracts,DApp development projects,IIT Kanpur certificate,Blockchain startup mentorship', 0, 0, '2026-05-10'),
