INSERT OR IGNORE INTO testimonials (user_name, user_title, user_company, content, course_id, rating, is_featured) VALUES 
  ('Ananya Krishnan', 'Senior Data Analyst', 'Google India', 'The MS in Data Science program transformed my career. Within 6 months of completion, I moved from a junior analyst role to leading a data team at Google. The hands-on projects and mentorship were invaluable.', 1, 5, 1),
  ('Rohit Menon', 'Product Manager', 'Amazon', 'The IIM Kozhikode management program gave me the strategic thinking skills I needed. The campus immersion was an incredible experience that connected me with brilliant minds.', 2, 5, 1),
  ('Deepika Nair', 'Full Stack Developer', 'Microsoft', 'I switched from a non-tech background to software development thanks to this program. The project-based curriculum and mock interviews prepared me perfectly for my role at Microsoft.', 3, 5, 1),
  ('Karthik Rajan', 'ML Engineer', 'NVIDIA', 'Dr. Ravindran''s teaching methodology at IIT Madras is exceptional. This program didn''t just teach me algorithms - it taught me to think like a researcher. Now I work on cutting-edge ML at NVIDIA.', 4, 5, 1),
  ('Meera Agarwal', 'Digital Marketing Head', 'Flipkart', 'MICA''s digital marketing program is industry-leading. The live campaign projects with real budgets gave me experience that no textbook could match.', 5, 5, 1),
  ('Siddharth Jain', 'CTO', 'HealthTech Startup', 'The cybersecurity program gave me the expertise to build secure systems from day one. Our startup handles sensitive health data, and this knowledge is critical.', 6, 4, 0),
  ('Pooja Sharma', 'VP Product', 'Razorpay', 'Duke CE''s product management program is world-class. The Silicon Valley immersion changed my perspective on building products. I was promoted within 3 months of completing the program.', 7, 5, 1),
  ('Arun Deshmukh', 'MBA Graduate', 'Deloitte', 'Getting an MBA from Liverpool Business School while working full-time seemed impossible, but the flexible learning format made it achievable. The ROI has been phenomenal.', 9, 5, 1);

