-- Course FAQs (for MS Data Science - course 1)
INSERT OR IGNORE INTO course_faqs (course_id, question, answer, sort_order) VALUES
  (1, 'What are the eligibility criteria for this program?', 'You need a bachelor degree in any discipline with minimum 50% marks. Basic knowledge of mathematics and statistics is preferred but not mandatory. Working professionals with 1+ years of experience are ideal candidates.', 1),
  (1, 'Is this an online or offline program?', 'This is a 100% online program with live sessions, recorded lectures, and hands-on projects. You can learn at your own pace while working. There are optional campus immersion sessions at IIIT Bangalore.', 2),
  (1, 'What kind of career support do you provide?', 'We offer comprehensive career assistance including resume building, mock interviews, LinkedIn profile optimization, job referrals with 300+ hiring partners, and 1-on-1 career mentoring sessions.', 3),
  (1, 'Can I pay in installments?', 'Yes! We offer no-cost EMI options starting from INR 8,999/month. We also have tie-ups with leading banks and NBFCs for education loans with attractive interest rates.', 4),
  (1, 'What tools and technologies will I learn?', 'You will gain hands-on experience with Python, R, SQL, Tableau, Power BI, TensorFlow, Scikit-learn, Spark, Hadoop, Git, Jupyter Notebooks, and cloud platforms like AWS and GCP.', 5);

-- Course FAQs (for Full Stack - course 3)
INSERT OR IGNORE INTO course_faqs (course_id, question, answer, sort_order) VALUES
  (3, 'Do I need prior coding experience?', 'No prior coding experience is required. The program starts from the fundamentals of HTML, CSS, and JavaScript. However, basic computer literacy and problem-solving skills are expected.', 1),
  (3, 'What is the project component like?', 'You will build 15+ real-world projects throughout the program, including a capstone project. Projects range from building responsive websites to full-stack e-commerce applications with payment integration.', 2),
  (3, 'Is there a job guarantee?', 'While we do not offer a literal job guarantee, our placement assistance program has a 94% placement rate within 6 months of program completion. We connect you with 300+ hiring partners including top tech companies.', 3),
  (3, 'How many hours per week do I need to dedicate?', 'Plan for approximately 10-15 hours per week. This includes live sessions (3-4 hours), self-paced learning (4-5 hours), and project work (3-5 hours). The flexible format allows you to learn alongside your job.', 4);

